def require_auth(f):
    """Decorator for authenticated routes with sanitized logging"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        
        if not auth_header:
            app.logger.warning(f"Missing authorization header for {request.url}")
            return jsonify({'error': 'Authorization header required'}), 401
        
        # Log sanitized auth attempt
        app.logger.info(f"Authentication attempt for endpoint: {request.endpoint}")
        
        # Simulate auth validation
        if not auth_header.startswith('Bearer '):
            app.logger.warning(f"Invalid authorization format for {request.url}")
            return jsonify({'error': 'Invalid authorization format'}), 401
        
        return f(*args, **kwargs)
    
    return decorated_function


@app.route('/login', methods=['POST'])
def login():
    """Login endpoint with sanitized logging"""
    if not request.is_json:
        app.logger.warning("Login attempt with non-JSON content type")
        return jsonify({'error': 'Content-Type must be application/json'}), 400
    
    data = request.get_json()
    username = data.get('username')
    
    if not username:
        app.logger.warning("Login attempt without username")
        return jsonify({'error': 'Username and password required'}), 400
    
    # Note: In production, never log actual passwords
    # This sanitizes them automatically via the logging middleware
    app.logger.info(f"Login attempt for user: {username}")
    
    # Simulate successful login
    token = f"token_{username}_{datetime.utcnow().timestamp()}"
    
    app.logger.info(f"Login successful for user: {username}")
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'username': username
    }), 200


